import re
from typing import List
from beeai import AgentMessage, AgentMemory

class SecureAgentMemory(AgentMemory):
    PII_REDACT_MAP = {
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b': '[EMAIL]',
        r'\b\d{3}-\d{2}-\d{4}\b': '[SSN]',
        r'\b\d{16}\b': '[CARD]',
        r'(?i)(api[-_]?key|token|secret|password)[\s:=]+[^\s]+': r'\1=[REDACTED]'
    }

    def _sanitize_content(self, content: str) -> str:
        for pattern, replacement in self.PII_REDACT_MAP.items():
            content = re.sub(pattern, replacement, content)
        return content

    def add_message(self, message: AgentMessage):
        message.content = self._sanitize_content(message.content)
        super().add_message(message)

from functools import wraps
from beeai.tools import tool

def secure_tool(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        # Sanitize all string parameters
        sanitized_kwargs = {}
        for key, value in kwargs.items():
            if isinstance(value, str):
                # Remove common secret patterns
                value = re.sub(r'(?i)(password|token|secret|key)[\s:=]*[^\s,]+', '[REDACTED]', value)
                value = re.sub(r'\b[A-Za-z0-9+/]{20,}={0,2}\b', '[BASE64_REDACTED]', value)
            sanitized_kwargs[key] = value

        return func(*args, **sanitized_kwargs)
    return wrapper

