import json
from beeai.agent import AgentState

class SecureAgentState(AgentState):
    SENSITIVE_FIELDS = {'user_email', 'api_key', 'private_data', 'credentials'}

    def to_json(self, redact_sensitive: bool = True) -> str:
        state_dict = self.__dict__.copy()

        if redact_sensitive:
            for field in list(state_dict.keys()):
                if any(sensitive in field.lower() for sensitive in self.SENSITIVE_FIELDS):
                    state_dict[field] = '[REDACTED]'

        return json.dumps(state_dict, default=str)
